from flask import Flask, request, redirect, url_for, session, flash
import os
from authlib.integrations.flask_client import OAuth

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', 'your_secret_key')

oauth = OAuth(app)

# Replace with your client configuration
client_id = 'your_client_id'
client_secret = 'your_client_secret'
authorization_base_url = 'https://provider.com/oauth/authorize'
token_url = 'https://provider.com/oauth/token'
domain = 'yourdomain.com'

# Configure the OAuth 2.0 client
oauth.register(
    name='provider',
    client_id=client_id,
    client_secret=client_secret,
    access_token_url=token_url,
    authorize_url=authorization_base_url,
    api_base_url='https://provider.com/api/',
    client_kwargs={'scope': 'read write'}
)

@app.route('/')
def index():
    redirect_uri = request.args.get('redirect_uri')
    if not redirect_uri:
        flash('Redirect URI is required.')
        return redirect(url_for('index'))

    if domain not in redirect_uri:
        flash('Invalid redirect URI. It must match the configured domain.')
        return redirect(url_for('index'))

    # Store the redirect URI in session for later use
    session['redirect_uri'] = redirect_uri

    authorization_url, state = oauth.provider.authorize_redirect(
        redirect_to='callback',
        redirect_uri=redirect_uri
    )
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    token = oauth.provider.authorize_access_token()
    session['oauth_token'] = token

    # Retrieve the redirect URI from session
    redirect_uri = session.get('redirect_uri')
    if not redirect_uri:
        flash('No redirect URI found in session.')
        return redirect(url_for('index'))

    return f'You are logged in with OAuth 2.0! Redirecting you to {redirect_uri}...'

if __name__ == '__main__':
    app.run(debug=True)